// Extract JSON array from Claude response
const text = $input.first().json.content[0].text;
// Strip markdown fences if present
const cleaned = text.replace(/^```json\n?|^```\n?|```$/gm, '').trim();
const concepts = JSON.parse(cleaned);
if (!Array.isArray(concepts) || concepts.length !== 14) {
  throw new Error(`Expected 14 concepts, got ${Array.isArray(concepts) ? concepts.length : 'non-array'}`);
}
// Embed index so Schedule Calculator can use it even inside Split In Batches
return concepts.map((c, index) => ({ json: { ...c, _idx: index } }));

// Assign scheduled_for: 2/day × 7 days, staggered 11am & 6pm PT (UTC-7)
// Day 0 = Monday (next day after Sunday cron)
const item = $input.first().json;
const idx = item._idx ?? $itemIndex; // prefer embedded index; fallback to $itemIndex
const dayOffset = Math.floor(idx / 2) + 1; // days from today (Mon-Sun)
const slotHour = idx % 2 === 0 ? 18 : 1;    // 11am PT = 18:00 UTC, 6pm PT = 01:00 UTC next day
const base = new Date();
base.setUTCDate(base.getUTCDate() + dayOffset);
base.setUTCHours(slotHour, 0, 0, 0);
const status = ['build_in_public', 'trades_to_tech'].includes(item.pillar) ? 'recording_needed' : 'draft';
// Remove internal tracking field before inserting
const { _idx, ...concept } = item;
return [{ json: { ...concept, scheduled_for: base.toISOString(), status } }];
